  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Dodge her E \u2014 E-knock her up, out-sustain her.", breakdown: "Dodge her E, E-knock her up, pick up blobs, and out-sustain her low-threat kit. Note her W can block your E.", dos: ["Dodge her E wall-stun", "E-knock her up (watch her W)", "Pick up blobs to sustain"], donts: ["E-dash into her active W", "Get R-knocked mid-combo", "Fall behind in scaling"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "E-Q + R her." }, hold: "Hold E for when her W is down \u2014 her W grounds + blocks your dash, so don\u2019t E into it.", tip: "Dodge her E and E-knock her up when her W is down \u2014 pick up blobs to out-sustain.", win: "E-knock her off her W and out-sustain." },
