  tahmkench: { diff: "EVEN", tone: "#e8b84b", tldr: "Dodge his tongue \u2014 E-knock him up, anti-heal.", breakdown: "Dodge his Q tongue, E-knock him up, anti-heal, and pick up blobs to out-sustain.", dos: ["Dodge his Q tongue", "E-knock him up", "Anti-heal his sustain"], donts: ["Get Q-stunned", "Fight into his W reactivate", "Eat free passive stacks"], key: { slot: "W", name: "Abyssal Dive", cd: "12s", note: "His escape + shield. Trade when down.", winT: "W DOWN", winS: "E-Q + R him." }, hold: "Hold E to knock him up \u2014 anti-heal his sustain and pick up blobs.", tip: "Dodge his Q tongue, E-knock him up, and anti-heal \u2014 out-sustain his tank kit.", win: "E-knock him and anti-heal." },
  zac: { diff: "MIRROR", tone: "#e8b84b", tldr: "Blob mirror \u2014 whoever lands E-knock + denies blobs wins.", breakdown: "Pure Zac mirror: it\u2019s an E-knock and blob-denial game. Whoever lands E and picks up more blobs wins.", dos: ["Win the E-knock race", "Deny his blobs", "Anti-heal his sustain"], donts: ["Let him eat your blobs", "Get E-knocked first", "Fall behind in scaling"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "Whoever lands E + denies blobs wins.", winT: "SLINGSHOT DOWN", winS: "E-Q + R him." }, hold: "Hold E to bait his \u2014 whoever lands the knockup and denies the other\u2019s blobs wins.", tip: "It\u2019s a blob-denial mirror \u2014 win the E-knock, steal his blobs, and anti-heal his sustain.", win: "Win the E-knock and deny his blobs." },
  // ===== MAGES, MARKSMEN & SPECIALISTS =====
  akali: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build MR \u2014 E-knock her off shroud, sustain.", breakdown: "Build MR, E-knock her up off her shroud, and pick up blobs to out-sustain her burst.", dos: ["Build MR", "E-knock her off shroud", "Pick up blobs to sustain"], donts: ["Fight her 6 with no MR", "Get Q-poked down", "Chase her into shroud"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. E-knock before it.", winT: "SHROUD DOWN", winS: "E-Q + R her." }, hold: "Hold E to knock her up before she shrouds \u2014 the knockup cancels her burst.", tip: "Build MR, E-knock her up off her shroud, and pick up blobs to out-sustain her.", win: "Build MR and E-knock her off shroud." },
