  gnar: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His %HP hurts \u2014 E-knock mini, respect Mega CC.", breakdown: "Gnar\u2019s %HP boomerang chunks you. E-knock mini-Gnar, build mixed, and dodge Mega.", dos: ["Build mixed resists", "E-knock mini-Gnar", "Dodge Mega\u2019s all-in"], donts: ["Get kited in mini form", "Fight Mega\u2019s all-in", "Stack pure HP vs %damage"], key: { slot: "R", name: "GNAR! (Mega Stun)", cd: "90s", note: "His Mega all-in. Dodge it.", winT: "MINI FORM", winS: "E-Q + R him." }, hold: "Hold E to knock up mini-Gnar \u2014 it stops his kite; dodge Mega\u2019s all-in.", tip: "His %-HP boomerang chunks you \u2014 E-knock mini-Gnar, build mixed, and dodge Mega.", win: "E-knock mini and dodge Mega." },
