  kayle: { diff: "EVEN", tone: "#e8b84b", tldr: "Both scale \u2014 E-knock her early, deny her CS.", breakdown: "Both scale. E-knock her off CS early, deny her farm, and pick up blobs to out-sustain.", dos: ["E-knock her off CS", "Deny her CS + XP", "Pick up blobs to sustain"], donts: ["Let her free-farm", "Fall behind in scaling", "Fight late from behind"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "E-Q + R her." }, hold: "Hold E to knock her off a CS \u2014 deny her farm and pick up blobs.", tip: "It\u2019s a scaling race \u2014 E-knock her off CS early and out-sustain her before her R.", win: "Deny her early and out-sustain her." },
  kennen: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 E-knock him, sustain his poke.", breakdown: "Build MR, E-knock him up, and pick up blobs to out-sustain his squishy kit.", dos: ["Build MR", "E-knock him up", "Pick up blobs to sustain"], donts: ["Eat free Q pokes", "Get triple-stunned", "Fall behind in scaling"], key: { slot: "E", name: "Lightning Rush", cd: "10s", note: "His escape. E-knock before it.", winT: "E DOWN", winS: "E-Q + R him." }, hold: "Hold E to knock him up before his E \u2014 pick up blobs and out-sustain.", tip: "Build MR, E-knock him up, and pick up blobs \u2014 out-sustain his squishy kit.", win: "Build MR and E-knock him." },
  quinn: { diff: "TRICKY", tone: "#ff8b3d", tldr: "She pokes + kites \u2014 E-knock her kite, all-in.", breakdown: "Quinn out-pokes you. E-knock her up (the long-range E catches her kite), and all-in early.", dos: ["E-knock her kite", "Pick up blobs to sustain", "All-in early"], donts: ["Fight into her blind", "Poke-war from range", "Let her kite you out"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. E-knock around it.", winT: "VAULT DOWN", winS: "E-Q + R her." }, hold: "Hold E to knock her up \u2014 the long-range E closes on her kite; then all-in.", tip: "E-knock her up (the long E catches her kite) and all-in early before she scales.", win: "E-knock her kite and all-in early." },
  rumble: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His %HP DoT hurts \u2014 build MR, E-knock him.", breakdown: "Rumble\u2019s flamespitter does %HP. Build MR, E-knock him up out of his flame, and dodge his R.", dos: ["Build MR", "E-knock him out of flame", "Dodge his R line"], donts: ["Stand in his flamespitter", "Stack pure HP vs %damage", "Sit in his R line"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "E-Q + R him." }, hold: "Hold E to knock him up out of his flamespitter range \u2014 build MR since his DoT is magic.", tip: "His %-HP flamespitter chunks you \u2014 build MR, E-knock him out of it, and dodge his Equalizer.", win: "Build MR and E-knock him out." },
  singed: { diff: "EVEN", tone: "#e8b84b", tldr: "Don\u2019t chase poison \u2014 E-knock him, out-sustain.", breakdown: "Never chase through poison. Build MR, E-knock him up when he commits, and pick up blobs.", dos: ["Build MR", "E-knock when he commits", "Pick up blobs to sustain"], donts: ["Chase through his Q poison", "Get E-flipped into goo", "Tunnel on the kill"], key: { slot: "E", name: "Fling", cd: "14s", note: "His flip. E-knock after it.", winT: "FLING DOWN", winS: "E-Q + R him." }, hold: "Hold E to knock him up when he commits \u2014 stop his kite and pick up blobs.", tip: "Don\u2019t chase his poison \u2014 build MR, E-knock him up when he over-commits, and out-sustain.", win: "E-knock his commit and out-sustain." },
  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 E-knock him, dodge his E root.", breakdown: "Build MR, E-knock him up, dodge his E root, and pick up blobs to out-sustain.", dos: ["Build MR", "E-knock him up", "Dodge his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Fall behind in scaling"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Trade when it\u2019s down.", winT: "ASCENSION DOWN", winS: "E-Q + R him." }, hold: "Hold E to knock him up \u2014 build MR, dodge his E root, and pick up blobs.", tip: "Build MR, E-knock him up, and dodge his E root \u2014 out-sustain when his R is down.", win: "Build MR and E-knock him." },
  teemo: { diff: "HARD", tone: "#ff5d6c", tldr: "His blind + %HP + kite \u2014 build MR, E-knock his kite.", breakdown: "Teemo blinds your autos, shrooms do %HP, and he kites. Build MR, E-knock him up (long-range catches kite).", dos: ["Build MR + dodge shrooms", "E-knock his kite (ignores blind)", "Pick up blobs to sustain"], donts: ["Auto into his blind", "Chase through shrooms", "Stack pure HP vs %damage"], key: { slot: "Q", name: "Blinding Dart", cd: "7s", note: "Blinds your autos. E-knock to close.", winT: "BLIND DOWN", winS: "E-Q + R him." }, hold: "Hold E to knock him up \u2014 the long-range E ignores his blind and catches his kite.", tip: "His blind only stops autos \u2014 E-knock him up (the long E ignores blind, catches his kite), build MR, and pick up blobs.", win: "E-knock his kite and build MR." },
