  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — slingshot him on the Heroic Swing cooldown and out-sustain on blobs.","breakdown":"Akshan plays around Heroic Swing. Charge E from fog as Heroic Swing goes down, Q-stretch the knock-together, and blob discipline makes every trade come back free. Doran’s Shield blunts the poke war.","dos":["E from fog when Heroic Swing is down","Pick up every blob","Q-stretch the double-hit"],"donts":["E into his peel","Let him stomp blobs","Fight with passive down"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"E-slingshot + blob sustain."},"win":"Slingshot him on the Heroic Swing cooldown and out-sustain on blobs."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then slingshot him on the Miasma cooldown and out-sustain on blobs.","breakdown":"Cassiopeia plays around Miasma. Charge E from fog as Miasma goes down, Q-stretch the knock-together, and blob discipline makes every trade come back free. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["E from fog when Miasma is down","Pick up every blob","Q-stretch the double-hit"],"donts":["E into his peel","Let him stomp blobs","Fight with passive down"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"E-slingshot + blob sustain."},"win":"Slingshot him on the Miasma cooldown and out-sustain on blobs."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — slingshot him on the Justice Punch cooldown and out-sustain on blobs.","breakdown":"Galio plays around Justice Punch. Charge E from fog as Justice Punch goes down, Q-stretch the knock-together, and blob discipline makes every trade come back free. Take Mercs / MR shard — his damage is magic.","dos":["E from fog when Justice Punch is down","Pick up every blob","Q-stretch the double-hit"],"donts":["E into his peel","Let him stomp blobs","Fight with passive down"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"E-slingshot + blob sustain."},"win":"Slingshot him on the Justice Punch cooldown and out-sustain on blobs."},
